scripts.script:
// No per-series colors, no foreColor, no grid.borderColor: the chart reads the
// --apx-* tokens from the cascade. theme.follow:'os' additionally tracks the
// operating system's light/dark setting with zero JS.

html:
Toggle light / dark
{{ charts[0] }}
Every color here comes from CSS --apx-* tokens (--apx-accent, --apx-fore, --apx-grid, --apx-surface) defined once in the stylesheet. The chart config sets no colors at all. The button flips a class that swaps the token values; with theme: { follow: 'os' } the chart also tracks the OS prefers-color-scheme automatically, no JS required.

chart.options:
chart: {
  height: 400,
  type: 'area',
  fontFamily: 'sans-serif',
  animations: { enabled: true },
  toolbar: { show: false },
},
theme: {
  follow: 'os',
},
stroke: { curve: 'smooth', width: 2 },
fill: { type: 'gradient', gradient: { opacityFrom: 0.35, opacityTo: 0.05 } },
dataLabels: { enabled: false },
title: {
  text: 'Weekly active users',
  align: 'left',
},
subtitle: {
  text: 'Colors come entirely from CSS --apx-* design tokens',
  align: 'left',
},
xaxis: {
  type: 'category',
  categories: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
},
grid: {
  borderColor: '#e0e0e0',
},

vanilla-js-script:
var root = document.documentElement
var stateEl = document.getElementById('state')

function currentMode() {
  return root.classList.contains('apx-dark') ? 'dark' : 'light'
}
function syncState() {
  stateEl.textContent = 'Current: ' + currentMode()
}
syncState()

document.getElementById('toggle').addEventListener('click', function () {
  root.classList.toggle('apx-dark')
  var mode = currentMode()
  // Re-render so the chart re-reads the (now swapped) --apx-* token values and
  // applies the matching built-in mode. With follow:'os' this happens on its
  // own when the OS setting changes.
  chart.updateOptions({ theme: { mode: mode } })
  syncState()
})
